  1‚Üí// Package fixture loads JSON fixture data into a PostgreSQL database.
  2‚Üí//
  3‚Üí// Fixture files are JSON arrays of objects (one file per table), optionally
  4‚Üí// xz-compressed. Files are named "<schema>.<table>.json" or
  5‚Üí// "<schema>.<table>.json.xz" and stored in a directory that is passed to
  6‚Üí// [Load] as an [io/fs.FS].
  7‚Üí//
  8‚Üí// Tables are loaded in FK-safe order. After all tables are populated, the
  9‚Üí// materialized views dataset_merged and dataset_latest are refreshed.
 10‚Üípackage fixture
 11‚Üí
 12‚Üíimport (
 13‚Üí	"bytes"
 14‚Üí	"context"
 15‚Üí	"encoding/json"
 16‚Üí	"fmt"
 17‚Üí	"io"
 18‚Üí	"io/fs"
 19‚Üí	"os/exec"
 20‚Üí	"strings"
 21‚Üí
 22‚Üí	"github.com/jackc/pgx/v5"
 23‚Üí	"github.com/jackc/pgx/v5/pgxpool"
 24‚Üí)
 25‚Üí
 26‚Üí// tableSpec defines a fixture table and how to load it.
 27‚Üítype tableSpec struct {
 28‚Üí	Schema string
 29‚Üí	Table  string
 30‚Üí}
 31‚Üí
 32‚Üí// loadOrder is the FK-safe order for loading fixture data. This must match
 33‚Üí// the extraction order in tools/samplesql/extractor.go.
 34‚Üívar loadOrder = []tableSpec{
 35‚Üí	{"location", "state"},
 36‚Üí	{"search_base", "ranking"},
 37‚Üí	{"search_base", "conference"},
 38‚Üí	{"search_base", "cip_data"},
 39‚Üí	{"search_base", "institution"},
 40‚Üí	{"search_base", "dataset"},
 41‚Üí	{"search_base", "annual_dataset"},
 42‚Üí	{"search_base", "institution_alias"},
 43‚Üí	{"location", "institution_normalized_alias"},
 44‚Üí	{"location", "zip_coordinates"},
 45‚Üí}
 46‚Üí
 47‚Üí// materializedViews are refreshed after all data is loaded.
 48‚Üívar materializedViews = []string{
 49‚Üí	"search_base.dataset_merged",
 50‚Üí	"search_base.dataset_latest",
 51‚Üí}
 52‚Üí
 53‚Üí// Load reads JSON fixture files from dataFS and inserts them into the database
 54‚Üí// in FK-safe order. The dataFS should contain files named
 55‚Üí// "<schema>.<table>.json" or "<schema>.<table>.json.xz".
 56‚Üí//
 57‚Üí// The database schema must already exist (migrations applied) before calling
 58‚Üí// Load.
 59‚Üífunc Load(ctx context.Context, pool *pgxpool.Pool, dataFS fs.FS) error {
 60‚Üí	// Discover column types for geometry and JSONB detection.
 61‚Üí	colTypes, err := discoverColumnTypes(ctx, pool)
 62‚Üí	if err != nil {
 63‚Üí		return err
 64‚Üí	}
 65‚Üí
 66‚Üí	for _, spec := range loadOrder {
 67‚Üí		data, err := readFixtureFile(dataFS, spec)
 68‚Üí		if err != nil {
 69‚Üí			return err
 70‚Üí		}
 71‚Üí		if data == nil {
 72‚Üí			continue // file not found ‚Äî skip
 73‚Üí		}
 74‚Üí
 75‚Üí		if err := loadTable(ctx, pool, spec, data, colTypes); err != nil {
 76‚Üí			return err
 77‚Üí		}
 78‚Üí	}
 79‚Üí
 80‚Üí	// Refresh materialized views.
 81‚Üí	for _, view := range materializedViews {
 82‚Üí		if _, err := pool.Exec(ctx, "REFRESH MATERIALIZED VIEW "+view); err != nil {
 83‚Üí			return fmt.Errorf("fixture: refresh %s: %w", view, err)
 84‚Üí		}
 85‚Üí	}
 86‚Üí
 87‚Üí	return nil
 88‚Üí}
 89‚Üí
 90‚Üí// LoadOrder returns the FK-safe table loading order. Useful for tests.
 91‚Üífunc LoadOrder() []string {
 92‚Üí	names := make([]string, len(loadOrder))
 93‚Üí	for i, spec := range loadOrder {
 94‚Üí		names[i] = spec.Schema + "." + spec.Table
 95‚Üí	}
 96‚Üí	return names
 97‚Üí}
 98‚Üí
 99‚Üí// readFixtureFile reads and decompresses a fixture file from the FS.
100‚Üí// Returns nil if the file does not exist.
101‚Üífunc readFixtureFile(dataFS fs.FS, spec tableSpec) ([]byte, error) {
102‚Üí	filename := fmt.Sprintf("%s.%s.json", spec.Schema, spec.Table)
103‚Üí	xzFilename := filename + ".xz"
104‚Üí
105‚Üí	// Try xz-compressed first.
106‚Üí	if data, err := fs.ReadFile(dataFS, xzFilename); err == nil {
107‚Üí		decompressed, err := xzDecompress(data)
108‚Üí		if err != nil {
109‚Üí			return nil, fmt.Errorf("fixture: decompress %s: %w", xzFilename, err)
110‚Üí		}
111‚Üí		return decompressed, nil
112‚Üí	}
113‚Üí
114‚Üí	// Try uncompressed.
115‚Üí	data, err := fs.ReadFile(dataFS, filename)
116‚Üí	if err != nil {
117‚Üí		return nil, nil //nolint:nilerr // file not found is not an error
118‚Üí	}
119‚Üí	return data, nil
120‚Üí}
121‚Üí
122‚Üí// xzDecompress decompresses xz data using the xz command-line tool.
123‚Üífunc xzDecompress(data []byte) ([]byte, error) {
124‚Üí	cmd := exec.Command("xz", "-dc") //nolint:gosec // G204: xz is a trusted system tool
125‚Üí	cmd.Stdin = bytes.NewReader(data)
126‚Üí	out, err := cmd.Output()
127‚Üí	if err != nil {
128‚Üí		return nil, fmt.Errorf("xz: %w", err)
129‚Üí	}
130‚Üí	return out, nil
131‚Üí}
132‚Üí
133‚Üí// columnInfo holds type metadata for a single column.
134‚Üítype columnInfo struct {
135‚Üí	UDTName  string // e.g. "geometry", "geography", "jsonb", "text"
136‚Üí	DataType string // e.g. "USER-DEFINED", "jsonb", "text"
137‚Üí}
138‚Üí
139‚Üí// discoverColumnTypes queries information_schema to build a map of
140‚Üí// schema.table.column ‚Üí columnInfo for all fixture tables.
141‚Üífunc discoverColumnTypes(ctx context.Context, pool *pgxpool.Pool) (map[string]columnInfo, error) {
142‚Üí	result := make(map[string]columnInfo)
143‚Üí
144‚Üí	// Build list of schemas and tables to query.
145‚Üí	schemas := make(map[string]bool)
146‚Üí	for _, spec := range loadOrder {
147‚Üí		schemas[spec.Schema] = true
148‚Üí	}
149‚Üí
150‚Üí	for schema := range schemas {
151‚Üí		rows, err := pool.Query(ctx,
152‚Üí			`SELECT table_name, column_name, data_type, udt_name
153‚Üí			 FROM information_schema.columns
154‚Üí			 WHERE table_schema = $1
155‚Üí			 ORDER BY table_name, ordinal_position`, schema)
156‚Üí		if err != nil {
157‚Üí			return nil, fmt.Errorf("fixture: discover columns for %s: %w", schema, err)
158‚Üí		}
159‚Üí
160‚Üí		for rows.Next() {
161‚Üí			var tableName, colName, dataType, udtName string
162‚Üí			if err := rows.Scan(&tableName, &colName, &dataType, &udtName); err != nil {
163‚Üí				rows.Close()
164‚Üí				return nil, fmt.Errorf("fixture: scan column info: %w", err)
165‚Üí			}
166‚Üí			key := fmt.Sprintf("%s.%s.%s", schema, tableName, colName)
167‚Üí			result[key] = columnInfo{UDTName: udtName, DataType: dataType}
168‚Üí		}
169‚Üí		rows.Close()
170‚Üí		if err := rows.Err(); err != nil {
171‚Üí			return nil, fmt.Errorf("fixture: iterate columns for %s: %w", schema, err)
172‚Üí		}
173‚Üí	}
174‚Üí
175‚Üí	return result, nil
176‚Üí}
177‚Üí
178‚Üí// loadTable parses JSON data and inserts rows into the target table.
179‚Üífunc loadTable(ctx context.Context, pool *pgxpool.Pool, spec tableSpec, data []byte, colTypes map[string]columnInfo) error {
180‚Üí	var rows []map[string]any
181‚Üí	if err := json.Unmarshal(data, &rows); err != nil {
182‚Üí		return fmt.Errorf("fixture: parse %s.%s: %w", spec.Schema, spec.Table, err)
183‚Üí	}
184‚Üí	if len(rows) == 0 {
185‚Üí		return nil
186‚Üí	}
187‚Üí
188‚Üí	qualifiedName := fmt.Sprintf("%s.%s", spec.Schema, spec.Table)
189‚Üí
190‚Üí	// Extract column order from the first row.
191‚Üí	columns := orderedKeys(rows[0])
192‚Üí
193‚Üí	// Check if any columns need special handling (geometry).
194‚Üí	hasGeo := false
195‚Üí	geoColumns := make(map[string]bool)
196‚Üí	for _, col := range columns {
197‚Üí		key := fmt.Sprintf("%s.%s.%s", spec.Schema, spec.Table, col)
198‚Üí		info, ok := colTypes[key]
199‚Üí		if ok && (info.UDTName == "geometry" || info.UDTName == "geography") {
200‚Üí			geoColumns[col] = true
201‚Üí			hasGeo = true
202‚Üí		}
203‚Üí	}
204‚Üí
205‚Üí	if hasGeo {
206‚Üí		return loadTableWithGeo(ctx, pool, qualifiedName, columns, rows, geoColumns)
207‚Üí	}
208‚Üí	return loadTableDirect(ctx, pool, qualifiedName, columns, rows, colTypes, spec)
209‚Üí}
210‚Üí
211‚Üí// loadTableDirect loads data using pgx CopyFrom for tables without geometry.
212‚Üífunc loadTableDirect(ctx context.Context, pool *pgxpool.Pool, qualifiedName string, columns []string, rows []map[string]any, colTypes map[string]columnInfo, spec tableSpec) error {
213‚Üí	// Build JSONB column set for proper marshaling.
214‚Üí	jsonbCols := make(map[string]bool)
215‚Üí	for _, col := range columns {
216‚Üí		key := fmt.Sprintf("%s.%s.%s", spec.Schema, spec.Table, col)
217‚Üí		info, ok := colTypes[key]
218‚Üí		if ok && info.UDTName == "jsonb" {
219‚Üí			jsonbCols[col] = true
220‚Üí		}
221‚Üí	}
222‚Üí
223‚Üí	copyRows := make([][]any, len(rows))
224‚Üí	for i, row := range rows {
225‚Üí		vals := make([]any, len(columns))
226‚Üí		for j, col := range columns {
227‚Üí			vals[j] = convertValue(row[col], jsonbCols[col])
228‚Üí		}
229‚Üí		copyRows[i] = vals
230‚Üí	}
231‚Üí
232‚Üí	parts := strings.SplitN(qualifiedName, ".", 2)
233‚Üí	copyCount, err := pool.CopyFrom(ctx,
234‚Üí		pgx.Identifier{parts[0], parts[1]},
235‚Üí		columns,
236‚Üí		pgx.CopyFromRows(copyRows),
237‚Üí	)
238‚Üí	if err != nil {
239‚Üí		return fmt.Errorf("fixture: copy %s: %w", qualifiedName, err)
240‚Üí	}
241‚Üí	if int(copyCount) != len(rows) {
242‚Üí		return fmt.Errorf("fixture: copy %s: expected %d rows, got %d", qualifiedName, len(rows), copyCount)
243‚Üí	}
244‚Üí
245‚Üí	return nil
246‚Üí}
247‚Üí
248‚Üí// loadTableWithGeo loads data using a staging table for geometry columns.
249‚Üí// Geometry values are stored as GeoJSON text in the JSON fixture, so we
250‚Üí// load into a temp table with text columns, then INSERT with ST_GeomFromGeoJSON.
251‚Üífunc loadTableWithGeo(ctx context.Context, pool *pgxpool.Pool, qualifiedName string, columns []string, rows []map[string]any, geoColumns map[string]bool) error {
252‚Üí	tx, err := pool.Begin(ctx)
253‚Üí	if err != nil {
254‚Üí		return fmt.Errorf("fixture: begin tx for %s: %w", qualifiedName, err)
255‚Üí	}
256‚Üí	defer tx.Rollback(ctx) //nolint:errcheck
257‚Üí
258‚Üí	// Create temp table mimicking the target but with text for geo columns.
259‚Üí	tempName := "fixture_staging"
260‚Üí	createCols := make([]string, len(columns))
261‚Üí	for i, col := range columns {
262‚Üí		// All columns are text in the staging table ‚Äî geo columns get
263‚Üí		// converted to geometry via ST_GeomFromGeoJSON in the final INSERT.
264‚Üí		createCols[i] = fmt.Sprintf("%s text", col)
265‚Üí	}
266‚Üí
267‚Üí	dropSQL := fmt.Sprintf("DROP TABLE IF EXISTS %s", tempName)
268‚Üí	if _, err := tx.Exec(ctx, dropSQL); err != nil {
269‚Üí		return fmt.Errorf("fixture: drop staging: %w", err)
270‚Üí	}
271‚Üí
272‚Üí	createSQL := fmt.Sprintf("CREATE TEMP TABLE %s (%s)", tempName, strings.Join(createCols, ", "))
273‚Üí	if _, err := tx.Exec(ctx, createSQL); err != nil {
274‚Üí		return fmt.Errorf("fixture: create staging for %s: %w", qualifiedName, err)
275‚Üí	}
276‚Üí
277‚Üí	// COPY into staging table with all values as text.
278‚Üí	copyRows := make([][]any, len(rows))
279‚Üí	for i, row := range rows {
280‚Üí		vals := make([]any, len(columns))
281‚Üí		for j, col := range columns {
282‚Üí			v := row[col]
283‚Üí			switch {
284‚Üí			case v == nil:
285‚Üí				vals[j] = nil
286‚Üí			case geoColumns[col]:
287‚Üí				// GeoJSON object ‚Üí JSON string
288‚Üí				b, err := json.Marshal(v)
289‚Üí				if err != nil {
290‚Üí					return fmt.Errorf("fixture: marshal geo %s row %d: %w", col, i, err)
291‚Üí				}
292‚Üí				vals[j] = string(b)
293‚Üí			default:
294‚Üí				vals[j] = toText(v)
295‚Üí			}
296‚Üí		}
297‚Üí		copyRows[i] = vals
298‚Üí	}
299‚Üí
300‚Üí	_, err = tx.CopyFrom(ctx,
301‚Üí		pgx.Identifier{tempName},
302‚Üí		columns,
303‚Üí		pgx.CopyFromRows(copyRows),
304‚Üí	)
305‚Üí	if err != nil {
306‚Üí		return fmt.Errorf("fixture: copy staging %s: %w", qualifiedName, err)
307‚Üí	}
308‚Üí
309‚Üí	// Build INSERT from staging with ST_GeomFromGeoJSON for geo columns.
310‚Üí	selectCols := make([]string, len(columns))
311‚Üí	for i, col := range columns {
312‚Üí		if geoColumns[col] {
313‚Üí			selectCols[i] = fmt.Sprintf("ST_GeomFromGeoJSON(%s) AS %s", col, col)
314‚Üí		} else {
315‚Üí			// Cast text back to original column types.
316‚Üí			selectCols[i] = col
317‚Üí		}
318‚Üí	}
319‚Üí
320‚Üí	insertSQL := fmt.Sprintf(
321‚Üí		"INSERT INTO %s (%s) SELECT %s FROM %s",
322‚Üí		qualifiedName,
323‚Üí		strings.Join(columns, ", "),
324‚Üí		strings.Join(selectCols, ", "),
325‚Üí		tempName,
326‚Üí	)
327‚Üí	if _, err := tx.Exec(ctx, insertSQL); err != nil {
328‚Üí		return fmt.Errorf("fixture: insert %s from staging: %w", qualifiedName, err)
329‚Üí	}
330‚Üí
331‚Üí	if _, err := tx.Exec(ctx, dropSQL); err != nil {
332‚Üí		return fmt.Errorf("fixture: cleanup staging: %w", err)
333‚Üí	}
334‚Üí
335‚Üí	if err := tx.Commit(ctx); err != nil {
336‚Üí		return fmt.Errorf("fixture: commit %s: %w", qualifiedName, err)
337‚Üí	}
338‚Üí
339‚Üí	return nil
340‚Üí}
341‚Üí
342‚Üí// toText converts a JSON-decoded value to its text representation for the
343‚Üí// staging table. All staging columns are text, so every value must be a string.
344‚Üífunc toText(v any) string {
345‚Üí	switch vt := v.(type) {
346‚Üí	case string:
347‚Üí		return vt
348‚Üí	case float64:
349‚Üí		return fmt.Sprintf("%v", vt)
350‚Üí	case bool:
351‚Üí		if vt {
352‚Üí			return "true"
353‚Üí		}
354‚Üí		return "false"
355‚Üí	default:
356‚Üí		b, err := json.Marshal(v)
357‚Üí		if err != nil {
358‚Üí			return fmt.Sprintf("%v", v)
359‚Üí		}
360‚Üí		return string(b)
361‚Üí	}
362‚Üí}
363‚Üí
364‚Üí// convertValue converts a JSON-decoded value to a pgx-compatible type.
365‚Üífunc convertValue(v any, isJSONB bool) any {
366‚Üí	if v == nil {
367‚Üí		return nil
368‚Üí	}
369‚Üí	if isJSONB {
370‚Üí		// JSONB columns: marshal the value back to a JSON byte slice
371‚Üí		// which pgx will send as JSONB.
372‚Üí		switch vt := v.(type) {
373‚Üí		case map[string]any, []any:
374‚Üí			b, err := json.Marshal(vt)
375‚Üí			if err != nil {
376‚Üí				return nil
377‚Üí			}
378‚Üí			return b
379‚Üí		case string:
380‚Üí			return []byte(vt)
381‚Üí		default:
382‚Üí			b, err := json.Marshal(v)
383‚Üí			if err != nil {
384‚Üí				return nil
385‚Üí			}
386‚Üí			return b
387‚Üí		}
388‚Üí	}
389‚Üí	return v
390‚Üí}
391‚Üí
392‚Üí// orderedKeys returns the keys of a map in a stable order.
393‚Üí// JSON object key order is not guaranteed, so we sort alphabetically.
394‚Üí// However, for fixture loading the order doesn't matter as long as it's
395‚Üí// consistent between the column list and the data rows.
396‚Üífunc orderedKeys(m map[string]any) []string {
397‚Üí	keys := make([]string, 0, len(m))
398‚Üí	for k := range m {
399‚Üí		keys = append(keys, k)
400‚Üí	}
401‚Üí	// Sort for determinism.
402‚Üí	sortStrings(keys)
403‚Üí	return keys
404‚Üí}
405‚Üí
406‚Üí// sortStrings sorts a string slice in place (insertion sort ‚Äî fine for small slices).
407‚Üífunc sortStrings(s []string) {
408‚Üí	for i := 1; i < len(s); i++ {
409‚Üí		for j := i; j > 0 && s[j] < s[j-1]; j-- {
410‚Üí			s[j], s[j-1] = s[j-1], s[j]
411‚Üí		}
412‚Üí	}
413‚Üí}
414‚Üí
415‚Üí// WriteJSON writes table data as JSON files to the given writer function.
416‚Üí// This is used by the fixtureutil CLI to generate JSON from database queries.
417‚Üífunc WriteJSON(w io.Writer, rows []map[string]any) error {
418‚Üí	enc := json.NewEncoder(w)
419‚Üí	enc.SetIndent("", "  ")
420‚Üí	return enc.Encode(rows)
421‚Üí}
