 13‚Üífunc main() {
 14‚Üí	databaseURL := flag.String("database-url", "", "PostgreSQL connection string (falls back to DATABASE_URL env var)")
 15‚Üí	limit := flag.Int("limit", 100, "number of institutions to sample")
 16‚Üí	output := flag.String("output", "", "output file path (default: stdout, copy format only)")
 17‚Üí	outputDir := flag.String("output-dir", "", "output directory for JSON format (one file per table)")
 18‚Üí	format := flag.String("format", "copy", "output format: copy or json")
 19‚Üí	seed := flag.Int("seed", 42, "random seed for deterministic sampling")
 20‚Üí	noCompress := flag.Bool("no-compress", false, "skip xz compression for JSON output")
 21‚Üí	flag.Parse()
 22‚Üí
 23‚Üí	if *format != "copy" && *format != "json" {
 24‚Üí		fmt.Fprintln(os.Stderr, "error: --format must be 'copy' or 'json'")
 25‚Üí		os.Exit(1)
 26‚Üí	}
 27‚Üí	if *format == "json" && *outputDir == "" {
 28‚Üí		fmt.Fprintln(os.Stderr, "error: --output-dir is required for JSON format")
 29‚Üí		os.Exit(1)
 30‚Üí	}
 31‚Üí
 32‚Üí	dsn := *databaseURL
 33‚Üí	if dsn == "" {
 34‚Üí		dsn = os.Getenv("DATABASE_URL")
 35‚Üí	}
 36‚Üí	if dsn == "" {
 37‚Üí		fmt.Fprintln(os.Stderr, "error: --database-url flag or DATABASE_URL env var is required")
 38‚Üí		os.Exit(1)
 39‚Üí	}
 40‚Üí	if *limit <= 0 {
 41‚Üí		fmt.Fprintln(os.Stderr, "error: --limit must be positive")
 42‚Üí		os.Exit(1)
 43‚Üí	}
 44‚Üí
 45‚Üí	ctx := context.Background()
 46‚Üí
 47‚Üí	conn, err := pgx.Connect(ctx, dsn)
 48‚Üí	if err != nil {
 49‚Üí		fmt.Fprintf(os.Stderr, "error: connect to database: %v\n", err)
 50‚Üí		os.Exit(1)
 51‚Üí	}
 52‚Üí	defer conn.Close(ctx)
 53‚Üí
 54‚Üí	fmt.Fprintf(os.Stderr, "sampling %d institutions (seed=%d)...\n", *limit, *seed)
 55‚Üí	unitIDs, err := sampleInstitutions(ctx, conn, *limit, *seed)
 56‚Üí	if err != nil {
 57‚Üí		fmt.Fprintf(os.Stderr, "error: %v\n", err)
 58‚Üí		os.Exit(1)
 59‚Üí	}
 60‚Üí	fmt.Fprintf(os.Stderr, "sampled %d institutions\n", len(unitIDs))
 61‚Üí
 62‚Üí	useGeoJSON := *format == "json"
 63‚Üí	fmt.Fprintln(os.Stderr, "extracting dependent tables...")
 64‚Üí	tables, err := extractAll(ctx, conn, unitIDs, useGeoJSON)
 65‚Üí	if err != nil {
 66‚Üí		fmt.Fprintf(os.Stderr, "error: %v\n", err)
 67‚Üí		os.Exit(1)
 68‚Üí	}
 69‚Üí
 70‚Üí	switch *format {
 71‚Üí	case "json":
 72‚Üí		fmt.Fprintln(os.Stderr, "writing JSON...")
 73‚Üí		if err := writeJSON(*outputDir, tables, !*noCompress); err != nil {
 74‚Üí			fmt.Fprintf(os.Stderr, "error: write output: %v\n", err)
 75‚Üí			os.Exit(1)
 76‚Üí		}
 77‚Üí	case "copy":
 78‚Üí		var w *os.File
 79‚Üí		if *output != "" {
 80‚Üí			w, err = os.Create(*output)
 81‚Üí			if err != nil {
 82‚Üí				fmt.Fprintf(os.Stderr, "error: create output file: %v\n", err)
 83‚Üí				os.Exit(1)
 84‚Üí			}
 85‚Üí			defer w.Close()
 86‚Üí		} else {
 87‚Üí			w = os.Stdout
 88‚Üí		}
 89‚Üí
 90‚Üí		fmt.Fprintln(os.Stderr, "writing COPY SQL...")
 91‚Üí		if err := writeCopySQL(w, tables, *seed, *limit); err != nil {
 92‚Üí			fmt.Fprintf(os.Stderr, "error: write output: %v\n", err)
 93‚Üí			os.Exit(1)
 94‚Üí		}
 95‚Üí	}
 96‚Üí
 97‚Üí	for _, t := range tables {
 98‚Üí		fmt.Fprintf(os.Stderr, "  %s.%s: %d rows\n", t.Schema, t.Table, len(t.Rows))
 99‚Üí	}
100‚Üí	fmt.Fprintln(os.Stderr, "done")
101‚Üí}
