  1‚Üípackage main
  2‚Üí
  3‚Üíimport (
  4‚Üí	"context"
  5‚Üí	"flag"
  6‚Üí	"fmt"
  7‚Üí	"log/slog"
  8‚Üí	"time"
  9‚Üí
 10‚Üí	"github.com/jackc/pgx/v5/pgxpool"
 11‚Üí	"github.com/ketang/kapow/tools/importer/internal/config"
 12‚Üí	"github.com/ketang/kapow/tools/importer/internal/fetch"
 13‚Üí)
 14‚Üí
 15‚Üí// Importer defines the interface that all data importers must implement.
 16‚Üítype Importer interface {
 17‚Üí	// Name returns the subcommand name (e.g. "nces", "rankings").
 18‚Üí	Name() string
 19‚Üí	// Description returns a short human-readable description.
 20‚Üí	Description() string
 21‚Üí	// Dependencies returns names of importers that must run before this one.
 22‚Üí	Dependencies() []string
 23‚Üí	// RegisterFlags adds importer-specific flags to the given FlagSet.
 24‚Üí	RegisterFlags(fs *flag.FlagSet)
 25‚Üí	// Run executes the import. It may use the pool for DB operations and the
 26‚Üí	// fetcher for downloading source data.
 27‚Üí	Run(ctx context.Context, cfg *config.Config, pool *pgxpool.Pool, fetcher *fetch.Fetcher) error
 28‚Üí}
 29‚Üí
 30‚Üí// registry holds all registered importers keyed by name.
 31‚Üívar registry = map[string]Importer{}
 32‚Üí
 33‚Üí// Register adds an importer to the registry. Panics on duplicate name.
 34‚Üífunc Register(imp Importer) {
 35‚Üí	name := imp.Name()
 36‚Üí	if _, exists := registry[name]; exists {
 37‚Üí		panic(fmt.Sprintf("importer: duplicate registration: %s", name))
 38‚Üí	}
 39‚Üí	registry[name] = imp
 40‚Üí}
 41‚Üí
 42‚Üí// Get returns a registered importer by name, or nil if not found.
 43‚Üífunc Get(name string) Importer {
 44‚Üí	return registry[name]
 45‚Üí}
 46‚Üí
 47‚Üí// All returns all registered importers.
 48‚Üífunc All() map[string]Importer {
 49‚Üí	return registry
 50‚Üí}
 51‚Üí
 52‚Üí// RunAll executes all importers in dependency order.
 53‚Üífunc RunAll(ctx context.Context, cfg *config.Config, pool *pgxpool.Pool, fetcher *fetch.Fetcher, skip, only map[string]bool) error {
 54‚Üí	ordered, err := topoSort(registry)
 55‚Üí	if err != nil {
 56‚Üí		return err
 57‚Üí	}
 58‚Üí
 59‚Üí	for _, imp := range ordered {
 60‚Üí		name := imp.Name()
 61‚Üí		if len(only) > 0 && !only[name] {
 62‚Üí			slog.Info("run-all: skipping (not in --only)", "importer", name)
 63‚Üí			continue
 64‚Üí		}
 65‚Üí		if skip[name] {
 66‚Üí			slog.Info("run-all: skipping (in --skip)", "importer", name)
 67‚Üí			continue
 68‚Üí		}
 69‚Üí
 70‚Üí		slog.Info("run-all: starting", "importer", name)
 71‚Üí		start := time.Now()
 72‚Üí		if err := imp.Run(ctx, cfg, pool, fetcher); err != nil {
 73‚Üí			return fmt.Errorf("run-all: %s: %w", name, err)
 74‚Üí		}
 75‚Üí		slog.Info("run-all: completed", "importer", name, "duration", time.Since(start).Round(time.Millisecond))
 76‚Üí	}
 77‚Üí
 78‚Üí	return nil
 79‚Üí}
 80‚Üí
 81‚Üí// topoSort returns importers in dependency order using Kahn's algorithm.
 82‚Üífunc topoSort(importers map[string]Importer) ([]Importer, error) {
 83‚Üí	// Build in-degree map and adjacency list.
 84‚Üí	inDegree := make(map[string]int)
 85‚Üí	dependents := make(map[string][]string) // dep -> list of importers that depend on it
 86‚Üí
 87‚Üí	for name, imp := range importers {
 88‚Üí		if _, ok := inDegree[name]; !ok {
 89‚Üí			inDegree[name] = 0
 90‚Üí		}
 91‚Üí		for _, dep := range imp.Dependencies() {
 92‚Üí			inDegree[name]++
 93‚Üí			dependents[dep] = append(dependents[dep], name)
 94‚Üí		}
 95‚Üí	}
 96‚Üí
 97‚Üí	// Start with importers that have no dependencies.
 98‚Üí	var queue []string
 99‚Üí	for name, deg := range inDegree {
100‚Üí		if deg == 0 {
101‚Üí			queue = append(queue, name)
102‚Üí		}
103‚Üí	}
104‚Üí
105‚Üí	var result []Importer
106‚Üí	for len(queue) > 0 {
107‚Üí		name := queue[0]
108‚Üí		queue = queue[1:]
109‚Üí		if imp, ok := importers[name]; ok {
110‚Üí			result = append(result, imp)
111‚Üí		}
112‚Üí		for _, dep := range dependents[name] {
113‚Üí			inDegree[dep]--
114‚Üí			if inDegree[dep] == 0 {
115‚Üí				queue = append(queue, dep)
116‚Üí			}
117‚Üí		}
118‚Üí	}
119‚Üí
120‚Üí	if len(result) != len(importers) {
121‚Üí		return nil, fmt.Errorf("importer: circular dependency detected")
122‚Üí	}
123‚Üí
124‚Üí	return result, nil
125‚Üí}
126‚Üí

  1‚Üípackage main
  2‚Üí
  3‚Üíimport (
  4‚Üí	"context"
  5‚Üí	"fmt"
  6‚Üí
  7‚Üí	"github.com/jackc/pgx/v5"
  8‚Üí)
  9‚Üí
 10‚Üí// tableData holds the result of extracting rows from a single table.
 11‚Üítype tableData struct {
 12‚Üí	Schema  string
 13‚Üí	Table   string
 14‚Üí	Columns []string
 15‚Üí	Rows    [][]any
 16‚Üí}
 17‚Üí
 18‚Üí// geoTables lists tables that have a PostGIS geometry/geography "coordinates"
 19‚Üí// column. When geoJSON is true, these tables use ST_AsGeoJSON to export
 20‚Üí// coordinates as portable GeoJSON instead of raw WKB hex.
 21‚Üívar geoTables = map[string]bool{
 22‚Üí	"search_base.institution":  true,
 23‚Üí	"location.zip_coordinates": true,
 24‚Üí}
 25‚Üí
 26‚Üí// extractAll extracts rows from all relevant tables in FK-safe order.
 27‚Üí// Lookup tables are dumped in full; institution-dependent tables are filtered
 28‚Üí// by the sampled unit_ids. When geoJSON is true, geometry columns are exported
 29‚Üí// as GeoJSON text instead of binary WKB.
 30‚Üífunc extractAll(ctx context.Context, conn *pgx.Conn, unitIDs []string, geoJSON bool) ([]tableData, error) {
 31‚Üí	// Extract location.state: all rows from the state table PLUS any state codes
 32‚Üí	// referenced by sampled institutions that are missing from the lookup table
 33‚Üí	// (e.g. territories like PR, GU).
 34‚Üí	stateData, err := extractCustomQuery(ctx, conn, "location", "state",
 35‚Üí		`SELECT code, name FROM (
 36‚Üí			SELECT code, name FROM location.state
 37‚Üí			UNION
 38‚Üí			SELECT DISTINCT i.state, i.state FROM search_base.institution i
 39‚Üí			WHERE i.unit_id = ANY($1)
 40‚Üí			AND NOT EXISTS (SELECT 1 FROM location.state s WHERE s.code = i.state)
 41‚Üí		) combined ORDER BY code`, unitIDs)
 42‚Üí	if err != nil {
 43‚Üí		return nil, err
 44‚Üí	}
 45‚Üí	results := []tableData{stateData}
 46‚Üí
 47‚Üí	type extraction struct {
 48‚Üí		schema   string
 49‚Üí		table    string
 50‚Üí		filtered bool // true = WHERE unit_id = ANY($1)
 51‚Üí	}
 52‚Üí
 53‚Üí	tables := []extraction{
 54‚Üí		{"search_base", "ranking", false},
 55‚Üí		{"search_base", "conference", false},
 56‚Üí		{"search_base", "cip_data", false},
 57‚Üí		{"search_base", "institution", true},
 58‚Üí		{"search_base", "dataset", true},
 59‚Üí		{"search_base", "annual_dataset", true},
 60‚Üí		{"search_base", "institution_alias", true},
 61‚Üí		{"location", "institution_normalized_alias", true},
 62‚Üí		{"location", "zip_coordinates", false},
 63‚Üí	}
 64‚Üí
 65‚Üí	for _, t := range tables {
 66‚Üí		qualifiedName := fmt.Sprintf("%s.%s", t.schema, t.table)
 67‚Üí		useGeoJSON := geoJSON && geoTables[qualifiedName]
 68‚Üí		td, err := extractTable(ctx, conn, t.schema, t.table, t.filtered, unitIDs, useGeoJSON)
 69‚Üí		if err != nil {
 70‚Üí			return nil, err
 71‚Üí		}
 72‚Üí		results = append(results, td)
 73‚Üí	}
 74‚Üí	return results, nil
 75‚Üí}
 76‚Üí
 77‚Üí// extractCustomQuery runs a custom SQL query and returns the result as tableData.
 78‚Üífunc extractCustomQuery(ctx context.Context, conn *pgx.Conn, schema, table, query string, args ...any) (tableData, error) {
 79‚Üí	qualifiedName := fmt.Sprintf("%s.%s", schema, table)
 80‚Üí	rows, err := conn.Query(ctx, query, args...)
 81‚Üí	if err != nil {
 82‚Üí		return tableData{}, fmt.Errorf("samplesql: query %s: %w", qualifiedName, err)
 83‚Üí	}
 84‚Üí	defer rows.Close()
 85‚Üí
 86‚Üí	fieldDescs := rows.FieldDescriptions()
 87‚Üí	columns := make([]string, len(fieldDescs))
 88‚Üí	for i, fd := range fieldDescs {
 89‚Üí		columns[i] = fd.Name
 90‚Üí	}
 91‚Üí
 92‚Üí	var dataRows [][]any
 93‚Üí	for rows.Next() {
 94‚Üí		values, err := rows.Values()
 95‚Üí		if err != nil {
 96‚Üí			return tableData{}, fmt.Errorf("samplesql: scan %s: %w", qualifiedName, err)
 97‚Üí		}
 98‚Üí		dataRows = append(dataRows, values)
 99‚Üí	}
100‚Üí	if err := rows.Err(); err != nil {
101‚Üí		return tableData{}, fmt.Errorf("samplesql: iterate %s: %w", qualifiedName, err)
102‚Üí	}
103‚Üí
104‚Üí	return tableData{
105‚Üí		Schema:  schema,
106‚Üí		Table:   table,
107‚Üí		Columns: columns,
108‚Üí		Rows:    dataRows,
109‚Üí	}, nil
110‚Üí}
111‚Üí
112‚Üí// extractTable queries a single table and returns its column names and rows.
113‚Üí// When geoJSON is true, geometry columns are wrapped with ST_AsGeoJSON to
114‚Üí// produce portable GeoJSON text instead of binary WKB.
115‚Üífunc extractTable(ctx context.Context, conn *pgx.Conn, schema, table string, filtered bool, unitIDs []string, geoJSON bool) (tableData, error) {
116‚Üí	qualifiedName := fmt.Sprintf("%s.%s", schema, table)
117‚Üí
118‚Üí	// When geoJSON mode is requested, we need to discover geometry columns
119‚Üí	// and replace them with ST_AsGeoJSON() calls in the SELECT list.
120‚Üí	selectExpr := "*"
121‚Üí	if geoJSON {
122‚Üí		cols, err := buildGeoJSONSelect(ctx, conn, schema, table)
123‚Üí		if err != nil {
124‚Üí			return tableData{}, err
125‚Üí		}
126‚Üí		if cols != "" {
127‚Üí			selectExpr = cols
128‚Üí		}
129‚Üí	}
130‚Üí
131‚Üí	var query string
132‚Üí	var rows pgx.Rows
133‚Üí	var err error
134‚Üí
135‚Üí	if filtered {
136‚Üí		query = fmt.Sprintf("SELECT %s FROM %s WHERE unit_id = ANY($1) ORDER BY 1", selectExpr, qualifiedName)
137‚Üí		rows, err = conn.Query(ctx, query, unitIDs)
138‚Üí	} else {
139‚Üí		query = fmt.Sprintf("SELECT %s FROM %s ORDER BY 1", selectExpr, qualifiedName)
140‚Üí		rows, err = conn.Query(ctx, query)
141‚Üí	}
142‚Üí	if err != nil {
143‚Üí		return tableData{}, fmt.Errorf("samplesql: query %s: %w", qualifiedName, err)
144‚Üí	}
145‚Üí	defer rows.Close()
146‚Üí
147‚Üí	fieldDescs := rows.FieldDescriptions()
148‚Üí	columns := make([]string, len(fieldDescs))
149‚Üí	for i, fd := range fieldDescs {
150‚Üí		columns[i] = fd.Name
151‚Üí	}
152‚Üí
153‚Üí	var dataRows [][]any
154‚Üí	for rows.Next() {
155‚Üí		values, err := rows.Values()
156‚Üí		if err != nil {
157‚Üí			return tableData{}, fmt.Errorf("samplesql: scan %s: %w", qualifiedName, err)
158‚Üí		}
159‚Üí		dataRows = append(dataRows, values)
160‚Üí	}
161‚Üí	if err := rows.Err(); err != nil {
162‚Üí		return tableData{}, fmt.Errorf("samplesql: iterate %s: %w", qualifiedName, err)
163‚Üí	}
164‚Üí
165‚Üí	return tableData{
166‚Üí		Schema:  schema,
167‚Üí		Table:   table,
168‚Üí		Columns: columns,
169‚Üí		Rows:    dataRows,
170‚Üí	}, nil
171‚Üí}
172‚Üí
173‚Üí// buildGeoJSONSelect queries information_schema to find geometry/geography
174‚Üí// columns and builds a SELECT list that wraps them with ST_AsGeoJSON().
175‚Üí// Returns "" if no geometry columns are found (caller should use SELECT *).
176‚Üífunc buildGeoJSONSelect(ctx context.Context, conn *pgx.Conn, schema, table string) (string, error) {
177‚Üí	rows, err := conn.Query(ctx,
178‚Üí		`SELECT column_name, udt_name
179‚Üí		 FROM information_schema.columns
180‚Üí		 WHERE table_schema = $1 AND table_name = $2
181‚Üí		 ORDER BY ordinal_position`, schema, table)
182‚Üí	if err != nil {
183‚Üí		return "", fmt.Errorf("samplesql: schema query %s.%s: %w", schema, table, err)
184‚Üí	}
185‚Üí	defer rows.Close()
186‚Üí
187‚Üí	var parts []string
188‚Üí	hasGeo := false
189‚Üí	for rows.Next() {
190‚Üí		var colName, udtName string
191‚Üí		if err := rows.Scan(&colName, &udtName); err != nil {
192‚Üí			return "", fmt.Errorf("samplesql: schema scan: %w", err)
193‚Üí		}
194‚Üí		if udtName == "geometry" || udtName == "geography" {
195‚Üí			parts = append(parts, fmt.Sprintf("ST_AsGeoJSON(%s)::jsonb AS %s", colName, colName))
196‚Üí			hasGeo = true
197‚Üí		} else {
198‚Üí			parts = append(parts, colName)
199‚Üí		}
200‚Üí	}
201‚Üí	if err := rows.Err(); err != nil {
202‚Üí		return "", fmt.Errorf("samplesql: schema iterate: %w", err)
203‚Üí	}
204‚Üí
205‚Üí	if !hasGeo {
206‚Üí		return "", nil
207‚Üí	}
208‚Üí
209‚Üí	result := ""
210‚Üí	for i, p := range parts {
211‚Üí		if i > 0 {
212‚Üí			result += ", "
213‚Üí		}
214‚Üí		result += p
215‚Üí	}
216‚Üí	return result, nil
217‚Üí}
218‚Üí

