10‚Üí// sampleInstitutions returns a deterministic pseudo-random sample of unit_ids
11‚Üí// from search_base.institution, ordered by md5(unit_id || seed).
12‚Üífunc sampleInstitutions(ctx context.Context, conn *pgx.Conn, limit int, seed int) ([]string, error) {
13‚Üí	query := `SELECT unit_id FROM search_base.institution ORDER BY md5(unit_id || $1) LIMIT $2`
14‚Üí	rows, err := conn.Query(ctx, query, fmt.Sprintf("%d", seed), limit)
15‚Üí	if err != nil {
16‚Üí		return nil, fmt.Errorf("samplesql: query institutions: %w", err)
17‚Üí	}
18‚Üí	defer rows.Close()
19‚Üí
20‚Üí	var unitIDs []string
21‚Üí	for rows.Next() {
22‚Üí		var id string
23‚Üí		if err := rows.Scan(&id); err != nil {
24‚Üí			return nil, fmt.Errorf("samplesql: scan unit_id: %w", err)
25‚Üí		}
26‚Üí		unitIDs = append(unitIDs, id)
27‚Üí	}
28‚Üí	if err := rows.Err(); err != nil {
29‚Üí		return nil, fmt.Errorf("samplesql: iterate institutions: %w", err)
30‚Üí	}
31‚Üí	return unitIDs, nil
32‚Üí}
