  9‚Üí
 10‚Üí// writeCopySQL writes all extracted table data in PostgreSQL COPY text format.
 11‚Üífunc writeCopySQL(w io.Writer, tables []tableData, seed, limit int) error {
 12‚Üí	// Header comment
 13‚Üí	if _, err := fmt.Fprintf(w, "-- samplesql: generated %s (seed=%d, limit=%d)\n",
 14‚Üí		time.Now().UTC().Format(time.RFC3339), seed, limit); err != nil {
 15‚Üí		return err
 16‚Üí	}
 17‚Üí	if _, err := fmt.Fprintln(w); err != nil {
 18‚Üí		return err
 19‚Üí	}
 20‚Üí
 21‚Üí	for _, td := range tables {
 22‚Üí		if len(td.Rows) == 0 {
 23‚Üí			continue
 24‚Üí		}
 25‚Üí
 26‚Üí		qualifiedName := fmt.Sprintf("%s.%s", td.Schema, td.Table)
 27‚Üí		colList := strings.Join(td.Columns, ", ")
 28‚Üí
 29‚Üí		if _, err := fmt.Fprintf(w, "COPY %s (%s) FROM stdin;\n", qualifiedName, colList); err != nil {
 30‚Üí			return err
 31‚Üí		}
 32‚Üí
 33‚Üí		for _, row := range td.Rows {
 34‚Üí			for i, val := range row {
 35‚Üí				if i > 0 {
 36‚Üí					if _, err := fmt.Fprint(w, "\t"); err != nil {
 37‚Üí						return err
 38‚Üí					}
 39‚Üí				}
 40‚Üí				if _, err := fmt.Fprint(w, formatCopyValue(val)); err != nil {
 41‚Üí					return err
 42‚Üí				}
 43‚Üí			}
 44‚Üí			if _, err := fmt.Fprintln(w); err != nil {
 45‚Üí				return err
 46‚Üí			}
 47‚Üí		}
 48‚Üí
 49‚Üí		if _, err := fmt.Fprintln(w, `\.`); err != nil {
 50‚Üí			return err
 51‚Üí		}
 52‚Üí		if _, err := fmt.Fprintln(w); err != nil {
 53‚Üí			return err
 54‚Üí		}
 55‚Üí	}
 56‚Üí
 57‚Üí	return nil
 58‚Üí}
 59‚Üí
 60‚Üí// formatCopyValue formats a single value for PostgreSQL COPY text format.
 61‚Üífunc formatCopyValue(v any) string {
 62‚Üí	if v == nil {
 63‚Üí		return `\N`
 64‚Üí	}
 65‚Üí
 66‚Üí	switch val := v.(type) {
 67‚Üí	case []byte:
 68‚Üí		// Binary data (e.g. PostGIS geography) ‚Äî output as hex
 69‚Üí		return fmt.Sprintf(`\x%x`, val)
 70‚Üí	case string:
 71‚Üí		return escapeCopyText(val)
 72‚Üí	case time.Time:
 73‚Üí		return val.Format("2006-01-02 15:04:05.999-07")
 74‚Üí	case bool:
 75‚Üí		if val {
 76‚Üí			return "t"
 77‚Üí		}
 78‚Üí		return "f"
 79‚Üí	case map[string]any:
 80‚Üí		// JSONB values are returned as map by pgx
 81‚Üí		return escapeCopyText(marshalJSON(val))
 82‚Üí	case []any:
 83‚Üí		// JSONB array values
 84‚Üí		return escapeCopyText(marshalJSON(val))
 85‚Üí	default:
 86‚Üí		return escapeCopyText(fmt.Sprintf("%v", val))
 87‚Üí	}
 88‚Üí}
 89‚Üí
 90‚Üí// escapeCopyText escapes special characters for PostgreSQL COPY text format.
 91‚Üífunc escapeCopyText(s string) string {
 92‚Üí	s = strings.ReplaceAll(s, `\`, `\\`)
 93‚Üí	s = strings.ReplaceAll(s, "\t", `\t`)
 94‚Üí	s = strings.ReplaceAll(s, "\n", `\n`)
 95‚Üí	s = strings.ReplaceAll(s, "\r", `\r`)
 96‚Üí	return s
 97‚Üí}
 98‚Üí
 99‚Üí// marshalJSON converts a Go value to a JSON string without importing encoding/json
100‚Üí// in the function signature ‚Äî keeps it simple.
101‚Üífunc marshalJSON(v any) string {
102‚Üí	// Use fmt for simple cases; for maps/slices, use encoding/json
103‚Üí	b, err := jsonMarshal(v)
104‚Üí	if err != nil {
105‚Üí		return fmt.Sprintf("%v", v)
106‚Üí	}
107‚Üí	return string(b)
108‚Üí}
