  2‚Üí
  3‚Üíimport (
  4‚Üí	"context"
  5‚Üí	"flag"
  6‚Üí	"fmt"
  7‚Üí	"log/slog"
  8‚Üí	"time"
  9‚Üí
 10‚Üí	"github.com/jackc/pgx/v5/pgxpool"
 11‚Üí	"github.com/ketang/kapow/tools/importer/internal/config"
 12‚Üí	"github.com/ketang/kapow/tools/importer/internal/fetch"
 13‚Üí)
 14‚Üí
 15‚Üí// Importer defines the interface that all data importers must implement.
 16‚Üítype Importer interface {
 17‚Üí	// Name returns the subcommand name (e.g. "nces", "rankings").
 18‚Üí	Name() string
 19‚Üí	// Description returns a short human-readable description.
 20‚Üí	Description() string
 21‚Üí	// Dependencies returns names of importers that must run before this one.
 22‚Üí	Dependencies() []string
 23‚Üí	// RegisterFlags adds importer-specific flags to the given FlagSet.
 24‚Üí	RegisterFlags(fs *flag.FlagSet)
 25‚Üí	// Run executes the import. It may use the pool for DB operations and the
 26‚Üí	// fetcher for downloading source data.
 27‚Üí	Run(ctx context.Context, cfg *config.Config, pool *pgxpool.Pool, fetcher *fetch.Fetcher) error
 28‚Üí}
 29‚Üí
 30‚Üí// registry holds all registered importers keyed by name.
 31‚Üívar registry = map[string]Importer{}
 32‚Üí
 33‚Üí// Register adds an importer to the registry. Panics on duplicate name.
 34‚Üífunc Register(imp Importer) {
 35‚Üí	name := imp.Name()
 36‚Üí	if _, exists := registry[name]; exists {
 37‚Üí		panic(fmt.Sprintf("importer: duplicate registration: %s", name))
 38‚Üí	}
 39‚Üí	registry[name] = imp
 40‚Üí}
 41‚Üí
 42‚Üí// Get returns a registered importer by name, or nil if not found.
 43‚Üífunc Get(name string) Importer {
 44‚Üí	return registry[name]
 45‚Üí}
 46‚Üí
 47‚Üí// All returns all registered importers.
 48‚Üífunc All() map[string]Importer {
 49‚Üí	return registry
 50‚Üí}
 51‚Üí
 52‚Üí// RunAll executes all importers in dependency order.
 53‚Üífunc RunAll(ctx context.Context, cfg *config.Config, pool *pgxpool.Pool, fetcher *fetch.Fetcher, skip, only map[string]bool) error {
 54‚Üí	ordered, err := topoSort(registry)
 55‚Üí	if err != nil {
 56‚Üí		return err
 57‚Üí	}
 58‚Üí
 59‚Üí	for _, imp := range ordered {
 60‚Üí		name := imp.Name()
 61‚Üí		if len(only) > 0 && !only[name] {
 62‚Üí			slog.Info("run-all: skipping (not in --only)", "importer", name)
 63‚Üí			continue
 64‚Üí		}
 65‚Üí		if skip[name] {
 66‚Üí			slog.Info("run-all: skipping (in --skip)", "importer", name)
 67‚Üí			continue
 68‚Üí		}
 69‚Üí
 70‚Üí		slog.Info("run-all: starting", "importer", name)
 71‚Üí		start := time.Now()
 72‚Üí		if err := imp.Run(ctx, cfg, pool, fetcher); err != nil {
 73‚Üí			return fmt.Errorf("run-all: %s: %w", name, err)
 74‚Üí		}
 75‚Üí		slog.Info("run-all: completed", "importer", name, "duration", time.Since(start).Round(time.Millisecond))
 76‚Üí	}
 77‚Üí
 78‚Üí	return nil
 79‚Üí}
 80‚Üí
 81‚Üí// topoSort returns importers in dependency order using Kahn's algorithm.
 82‚Üífunc topoSort(importers map[string]Importer) ([]Importer, error) {
 83‚Üí	// Build in-degree map and adjacency list.
 84‚Üí	inDegree := make(map[string]int)
 85‚Üí	dependents := make(map[string][]string) // dep -> list of importers that depend on it
 86‚Üí
 87‚Üí	for name, imp := range importers {
 88‚Üí		if _, ok := inDegree[name]; !ok {
 89‚Üí			inDegree[name] = 0
 90‚Üí		}
 91‚Üí		for _, dep := range imp.Dependencies() {
 92‚Üí			inDegree[name]++
 93‚Üí			dependents[dep] = append(dependents[dep], name)
 94‚Üí		}
 95‚Üí	}
 96‚Üí
 97‚Üí	// Start with importers that have no dependencies.
 98‚Üí	var queue []string
 99‚Üí	for name, deg := range inDegree {
100‚Üí		if deg == 0 {
101‚Üí			queue = append(queue, name)
102‚Üí		}
103‚Üí	}
104‚Üí
105‚Üí	var result []Importer
106‚Üí	for len(queue) > 0 {
107‚Üí		name := queue[0]
108‚Üí		queue = queue[1:]
109‚Üí		if imp, ok := importers[name]; ok {
110‚Üí			result = append(result, imp)
111‚Üí		}
112‚Üí		for _, dep := range dependents[name] {
113‚Üí			inDegree[dep]--
114‚Üí			if inDegree[dep] == 0 {
115‚Üí				queue = append(queue, dep)
116‚Üí			}
117‚Üí		}
118‚Üí	}
119‚Üí
120‚Üí	if len(result) != len(importers) {
121‚Üí		return nil, fmt.Errorf("importer: circular dependency detected")
122‚Üí	}
123‚Üí
124‚Üí	return result, nil
125‚Üí}
